mapper.select:
		/*
             SQL ID : AsmntProTeamDAO.selectObject
             	설  명 : 단건 조회
         */	



				AND A.STD_ID = #{stdNo}


				AND A.STD_ID = ( SELECT STD_ID
     							   FROM TB_LMS_ATNDLC_SBJCT
    							  WHERE USER_ID = #{userId}
    								AND ATNDLC_STSCD = 'S'
    								AND SBJCT_ID = #{crsCreCd})

		/*
             SQL ID : AsmntProTeamDAO.selectTeamCd
             	설  명 : 대상자 팀코드 조회
         */		
		SELECT TEAM.TEAM_ID
		    , MBR.USER_ID
		FROM TB_LMS_TEAM TEAM
			JOIN TB_LMS_TEAM_MBR MBR ON MBR.TEAM_ID = TEAM.TEAM_ID
		WHERE TEAM.LRN_GRP_ID = #{lrnGrpId}
			AND MBR.USER_ID = #{userId}

mapper.insert:
		/*
             SQL ID : AsmntProTeamDAO.insertTarget
             	설  명 : 과제 대상자 등록
         */
		INSERT INTO TB_LMS_ASMT_TRGT (
			ASMT_SBMSN_TRGT_ID
			, ASMT_ID
			, USER_ID
			, TEAM_ID
			, REG_DTTM
			, RGTR_ID
		) VALUES
		(
			#{asmtSbmsnTrgtId}
			, #{asmtId}
			, #{userId}
			, #{teamId}
			, FN_DTTM()
			, #{rgtrId}
		)

		/*
             SQL ID : AsmntProTeamDAO.insertTargetList
             	설  명 : 과제 대상자 목록 등록
         */
		INSERT INTO TB_LMS_ASMT_TRGT (
			ASMT_SBMSN_TRGT_ID
		  , ASMT_ID
		  , USER_ID
		  , TEAM_ID
		  , REG_DTTM
		  , RGTR_ID
		)

		SELECT
			#{item.asmtSbmsnTrgtId}
		  , #{item.asmtId}
		  , #{item.userId}
		  , #{item.teamId}
		  , FN_DTTM()
		  , #{item.rgtrId}
		FROM DUAL
